class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def _build(values):
    head = None
    for v in reversed(values):
        head = ListNode(v, head)
    return head

def _to_list(head):
    vals = []
    while head:
        vals.append(head.val)
        head = head.next
    return vals
